public int maxPrizes(int[] prizePositions, int k) {
    int n = prizePositions.length;
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        int left_segment_end = prizePositions[i] + k;
        int right_segment_start = Arrays.binarySearch(prizePositions, left_segment_end + 1);
        if (right_segment_start < 0) {
            right_segment_start = -right_segment_start - 1;
        }
        int right_segment_end = prizePositions[right_segment_start] + k;
        ans = Math.max(ans, Arrays.binarySearch(prizePositions, right_segment_end + 1)
                       - Arrays.binarySearch(prizePositions, prizePositions[i]));
    }
    return ans;
}
```

